from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct

app = Flask(__name__)

# Initialize Web3. A provider is not strictly necessary for offline signature recovery,
# but it's good practice to have a Web3 instance available.
# We'll use `Web3.eth.account.recover_message` which is a static method essentially.
w3 = Web3()

@app.route('/verify-signature', methods=['POST'])
def verify_signature():
    """
    Verifies an Ethereum wallet signature for authentication.
    Expects a JSON payload with 'message', 'signature', and 'address'.
    """
    data = request.get_json()

    if not data:
        return jsonify({"status": "error", "message": "Invalid JSON payload"}), 400

    message = data.get('message')
    signature = data.get('signature')
    address = data.get('address')

    if not all([message, signature, address]):
        return jsonify({
            "status": "error",
            "message": "Missing required fields: 'message', 'signature', and 'address'."
        }), 400

    try:
        # Convert the provided address to checksum format for robust comparison.
        # This handles potential case differences in addresses.
        checksum_address = Web3.to_checksum_address(address)

        # Encode the message according to the Ethereum signed message standard (EIP-191).
        # This adds the "\x19Ethereum Signed Message:\n<length>" prefix.
        # This is crucial for correctly recovering the address if the message was signed
        # using web3.eth.sign or similar methods.
        encoded_message = encode_defunct(text=message)

        # Recover the signer's address from the signature and the original message.
        recovered_address = w3.eth.account.recover_message(
            encoded_message,
            signature=signature
        )

        # Compare the recovered address with the address provided by the user.
        if recovered_address == checksum_address:
            return jsonify({
                "status": "success",
                "message": "Signature verified successfully.",
                "recovered_address": recovered_address,
                "expected_address": checksum_address
            }), 200
        else:
            return jsonify({
                "status": "error",
                "message": "Signature verification failed: Recovered address does not match provided address.",
                "recovered_address": recovered_address,
                "expected_address": checksum_address
            }), 401 # Unauthorized

    except ValueError as e:
        # This typically catches errors related to malformed signatures,
        # invalid message formats, or other cryptographic issues during recovery.
        return jsonify({
            "status": "error",
            "message": f"Signature verification failed: Invalid signature or message format. Details: {str(e)}",
            "signature_provided": signature,
            "message_text_provided": message
        }), 400
    except Exception as e:
        # Catch any other unexpected errors during the process.
        return jsonify({
            "status": "error",
            "message": f"An unexpected server error occurred: {str(e)}"
        }), 500

if __name__ == '__main__':
    # Run the Flask app.
    # For production, use a production-ready WSGI server like Gunicorn or uWSGI.
    # debug=True should not be used in production.
    app.run(debug=True, port=5000)